import * as k8s from '@pulumi/kubernetes';

export function setupPrometheus(params: {
  k8sProvider: k8s.Provider;
  namespace: k8s.core.v1.Namespace;
  storageClassName?: string;
  resourceNameSuffix?: string;
  disableAlertmanager?: boolean;
  disablePushgateway?: boolean;
  nodeExporterPriorityClassName?: string;
}) {
  new k8s.helm.v3.Chart(
    `prometheus${params.resourceNameSuffix ?? ''}`,
    {
      namespace: params.namespace.metadata.name,
      chart: 'prometheus',
      // renovate: chart="prometheus" repo="https://prometheus-community.github.io/helm-charts"
      version: '27.52.0',
      fetchOpts: {
        repo: 'https://prometheus-community.github.io/helm-charts',
      },
      values: {
        // Monitors ConfigMap changes and POSTs to a URL
        configmapReload: {
          prometheus: {
            resources: {
              requests: {
                cpu: '10m',
                memory: '30Mi',
              },
              limits: {
                cpu: '50m',
                memory: '100Mi',
              },
            },
          },
        },
        // Prometheus server configuration
        server: {
          // Prometheus data retention period (default if not specified is 15 days)
          retention: '60d',
          // Prometheus' data retention size. Supported units: B, KB, MB, GB, TB, PB, EB.
          retentionSize: '60GB',

          persistentVolume: {
            size: '64Gi',
            ...(params.storageClassName ? { storageClass: params.storageClassName } : {}),
          },
          resources: {
            requests: {
              cpu: '100m',
              memory: '2Gi',
            },
            limits: {
              cpu: '500m',
              memory: '5Gi',
            },
          },
          tolerations: [
            {
              key: 'kula.app/instance-capacity-type',
              operator: 'Equal',
              value: 'SPOT',
              effect: 'NoSchedule',
            },
          ],
        },
        // -- Sub Charts
        // alertmanager sub-chart configurable values
        // Please see https://github.com/prometheus-community/helm-charts/tree/main/charts/alertmanager
        alertmanager: {
          enabled: params.disableAlertmanager !== true,
          resources: {
            requests: {
              cpu: '20m',
              memory: '64Mi',
            },
            limits: {
              cpu: '100m',
              memory: '128Mi',
            },
          },
          affinity: {
            // Add node affinity to prefer SPOT instances for scheduling
            nodeAffinity: {
              preferredDuringSchedulingIgnoredDuringExecution: [
                {
                  weight: 10,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['SPOT'],
                      },
                    ],
                  },
                },
                {
                  weight: 5,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['ON_DEMAND'],
                      },
                    ],
                  },
                },
              ],
            },
          },
          // Define the toleration to indicate that this workload can be scheduled on on-demand instances and spot instances
          tolerations: [
            {
              key: 'kula.app/instance-capacity-type',
              operator: 'Equal',
              value: 'SPOT',
              effect: 'NoSchedule',
            },
          ],
        },
        // kube-state-metrics sub-chart configurable values
        // Please see https://github.com/prometheus-community/helm-charts/tree/main/charts/kube-state-metrics
        'kube-state-metrics': {
          resources: {
            requests: {
              cpu: '50m',
              memory: '50Mi',
            },
            limits: {
              cpu: '100m',
              memory: '100Mi',
            },
          },
          affinity: {
            // Add node affinity to prefer SPOT instances for scheduling
            nodeAffinity: {
              preferredDuringSchedulingIgnoredDuringExecution: [
                {
                  weight: 10,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['SPOT'],
                      },
                    ],
                  },
                },
                {
                  weight: 5,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['ON_DEMAND'],
                      },
                    ],
                  },
                },
              ],
            },
          },
          // Define the toleration to indicate that this workload can be scheduled on on-demand instances and spot instances
          tolerations: [
            {
              key: 'kula.app/instance-capacity-type',
              operator: 'Equal',
              value: 'SPOT',
              effect: 'NoSchedule',
            },
          ],
        },
        // prometheus-node-exporter sub-chart configurable values
        // Please see https://github.com/prometheus-community/helm-charts/tree/main/charts/prometheus-node-exporter
        'prometheus-node-exporter': {
          extraArgs: ['--log.level=debug'],
          ...(params.nodeExporterPriorityClassName ? { priorityClassName: params.nodeExporterPriorityClassName } : {}),
          resources: {
            requests: {
              cpu: '20m',
              memory: '30Mi',
            },
            limits: {
              cpu: '100m',
              memory: '50Mi',
            },
          },
        },
        // prometheus-pushgateway sub-chart configurable values
        // Please see https://github.com/prometheus-community/helm-charts/tree/main/charts/prometheus-pushgateway
        'prometheus-pushgateway': {
          enabled: params.disablePushgateway !== true,
          resources: {
            requests: {
              cpu: '20m',
              memory: '50Mi',
            },
            limits: {
              cpu: '100m',
              memory: '100Mi',
            },
          },
          affinity: {
            // Add node affinity to prefer SPOT instances for scheduling
            nodeAffinity: {
              preferredDuringSchedulingIgnoredDuringExecution: [
                {
                  weight: 10,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['SPOT'],
                      },
                    ],
                  },
                },
                {
                  weight: 5,
                  preference: {
                    matchExpressions: [
                      {
                        key: 'kula.app/instance-capacity-type',
                        operator: 'In',
                        values: ['ON_DEMAND'],
                      },
                    ],
                  },
                },
              ],
            },
          },
          // Define the toleration to indicate that this workload can be scheduled on on-demand instances and spot instances
          tolerations: [
            {
              key: 'kula.app/instance-capacity-type',
              operator: 'Equal',
              value: 'SPOT',
              effect: 'NoSchedule',
            },
          ],
        },
      },
    },
    {
      provider: params.k8sProvider,
    },
  );
}

