import * as k8s from '@pulumi/kubernetes';
import { StackNames } from '../../util/StackNames';
import { ExtendedStackReference } from '../../util/createNamedStackRef';
import { createProdHel1TwoProvider } from '../../util/createProdHel1TwoProvider';
import { createDNSRecords } from './grafana/createDNSRecords';
import { createGrafana } from './grafana/createGrafana';
import { createIngress } from './grafana/createIngress';
import { SharedAnalyticsStackOutput } from './interfaces/SharedAnalyticsStackOutput';
import { setupNamespace } from './setupNamespace';
import { setupPrometheus } from './setupPrometheus';

export default function setupSharedAnalyticsStack(): SharedAnalyticsStackOutput {
  // Get output of dependency stacks
  const sharedStackOutput = new ExtendedStackReference(StackNames.Shared).requireTypedOutput('sharedStackOutput');

  // Prepare access to Kubernetes Cluster
  const k8sProvider = new k8s.Provider('shared-k8s-cluster', {
    kubeconfig: sharedStackOutput.kubeConfig,
  });

  // Setup Kubernetes Namespace
  const namespace = setupNamespace({
    k8sProvider: k8sProvider,
  });

  // Setup Services
  setupPrometheus({
    k8sProvider: k8sProvider,
    namespace: namespace,
    nodeExporterPriorityClassName: 'kula-shared-critical',
  });

  // --- prod-hel1-2 cluster ---

  const prodHel1TwoProvider = createProdHel1TwoProvider();

  const prodHel1TwoNamespace = setupNamespace({
    k8sProvider: prodHel1TwoProvider,
    resourceNameSuffix: '-prod-hel1-2',
  });

  setupPrometheus({
    k8sProvider: prodHel1TwoProvider,
    namespace: prodHel1TwoNamespace,
    storageClassName: 'longhorn',
    resourceNameSuffix: '-prod-hel1-2',
    disableAlertmanager: true,
    disablePushgateway: true,
  });

  const grafanaService = createGrafana({
    k8sProvider: prodHel1TwoProvider,
    namespace: prodHel1TwoNamespace.metadata.name,
  });

  createIngress({
    k8sProvider: prodHel1TwoProvider,
    namespace: prodHel1TwoNamespace.metadata.name,
    grafanaService: grafanaService,
  });

  createDNSRecords();

  return {};
}

